+    .prepare(
+      `SELECT 1
+       FROM workspace_deployment_events
+       WHERE workspace_id = ? AND deployment_id = ? AND event_type = ?
+       LIMIT 1`
+    )
+    .bind(workspaceId, deploymentId, eventType)
+    .first<{ '1': number }>();
+
+  return Boolean(record);
+}
